diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..259b8aa28cbd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -1860,6 +1860,16 @@ Instruction *InstCombinerImpl::foldICmpAndConstConst(ICmpInst &Cmp,
   if (Instruction *I = foldICmpAndShift(Cmp, And, C1, *C2))
     return I;

+  // (icmp eq/ne (and X, Mask), C) where Mask has exactly one zero bit,
+  // C is a power of two, and (C & ~Mask) == 0.
+  // Transform to (icmp eq/ne (and X, C), C).
+  if (Cmp.isEquality() && C2->popcount() == C2->getBitWidth() - 1 &&
+      C1.isPowerOf2() && (C1 & ~*C2) == 0) {
+    Value *AndC = Builder.CreateAnd(X, ConstantInt::get(X->getType(), C1));
+    return new ICmpInst(Cmp.getPredicate(), AndC,
+                        ConstantInt::get(AndC->getType(), C1));
+  }
+
   // (icmp pred (and (or (lshr A, B), A), 1), 0) -->
   // (icmp pred (and A, (or (shl 1, B), 1), 0))
   //
@@ -1929,7 +1939,6 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
                                                    const APInt &C) {
   if (Instruction *I = foldICmpAndConstConst(Cmp, And, C))
     return I;
-
   const ICmpInst::Predicate Pred = Cmp.getPredicate();
   bool TrueIfNeg;
   if (isSignBitCheck(Pred, C, TrueIfNeg)) {
@@ -2016,6 +2025,39 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
                           ConstantInt::get(MaskA->getType(), NewComperand));
     }
   }
+  // (icmp eq/ne (and (add A, -1), Mask), 0) where Mask has exactly one zero bit
+  // not at bit 0 -> (icmp eq/ne (and A, Mask), 1 & Mask)
+  {
+    Value *A;
+    const APInt *Addend, *Msk;
+    if (match(And, m_c_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
+                           m_APInt(Msk)))) {
+      if (Cmp.isEquality() && C.isZero() && Addend->isAllOnes() &&
+          Msk->popcount() == Msk->getBitWidth() - 1 &&
+          (~*Msk).countTrailingZeros() != 0) {
+        APInt NewComperand = (C - *Addend) & *Msk;
+        Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
+        return new ICmpInst(Pred, MaskA,
+                            ConstantInt::get(MaskA->getType(), NewComperand));
+      }
+    }
+  }
+  // (icmp eq/ne (and X, Mask), C) where Mask has exactly one zero bit,
+  // C is a power of two, and C & Mask == C (i.e., C's bit is not the zero bit).
+  // Transform to (icmp eq/ne (and X, C), C).
+  {
+    Value *X;
+    const APInt *Mask, *CmpRHS;
+    if (match(And, m_And(m_Value(X), m_APInt(Mask))) &&
+        Cmp.isEquality() &&
+        Mask->popcount() == Mask->getBitWidth() - 1 &&
+        C.isPowerOf2() && (C & ~*Mask) == 0) {
+      // Zero bit position is where Mask has 0.
+      // Since C's bit is not that zero bit (by the mask), we can simplify.
+      Value *AndC = Builder.CreateAnd(X, ConstantInt::get(X->getType(), C));
+      return new ICmpInst(Pred, AndC, ConstantInt::get(AndC->getType(), C));
+    }
+  }

   return nullptr;
 }

