  2039 | /// Fold icmp eq/ne (or (xor/sub (X1, X2), xor/sub (X3, X4))), 0.
  2040 | static Value *foldICmpOrXorSubChain(ICmpInst &Cmp, BinaryOperator *Or,
  2041 |                                     InstCombiner::BuilderTy &Builder) {
  2042 |   // Are we using xors or subs to bitwise check for a pair or pairs of
  2043 |   // (in)equalities? Convert to a shorter form that has more potential to be
  2044 |   // folded even further.
  2045 |   // ((X1 ^/- X2) || (X3 ^/- X4)) == 0 --> (X1 == X2) && (X3 == X4)
  2046 |   // ((X1 ^/- X2) || (X3 ^/- X4)) != 0 --> (X1 != X2) || (X3 != X4)
  2047 |   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) == 0 -->
  2048 |   // (X1 == X2) && (X3 == X4) && (X5 == X6)
  2049 |   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) != 0 -->
  2050 |   // (X1 != X2) || (X3 != X4) || (X5 != X6)
  2051 |   SmallVector<std::pair<Value *, Value *>, 2> CmpValues;
  2052 |   SmallVector<Value *, 16> WorkList(1, Or);
  2053 | 
  2054 |   while (!WorkList.empty()) {
  2055 |     auto MatchOrOperatorArgument = [&](Value *OrOperatorArgument) {
  2056 |       Value *Lhs, *Rhs;
  2057 | 
  2058 |       if (match(OrOperatorArgument,
  2059 |                 m_OneUse(m_Xor(m_Value(Lhs), m_Value(Rhs))))) {
  2060 |         CmpValues.emplace_back(Lhs, Rhs);
  2061 |         return;
  2062 |       }
  2063 | 
  2064 |       if (match(OrOperatorArgument,
  2065 |                 m_OneUse(m_Sub(m_Value(Lhs), m_Value(Rhs))))) {
  2066 |         CmpValues.emplace_back(Lhs, Rhs);
  2067 |         return;
  2068 |       }
  2069 | 
  2070 |       WorkList.push_back(OrOperatorArgument);
  2071 |     };
  2072 | 
  2073 |     Value *CurrentValue = WorkList.pop_back_val();
  2074 |     Value *OrOperatorLhs, *OrOperatorRhs;
  2075 | 
  2076 |     if (!match(CurrentValue,
  2077 |                m_Or(m_Value(OrOperatorLhs), m_Value(OrOperatorRhs)))) {
  2078 |       return nullptr;
  2079 |     }
  2080 | 
  2081 |     MatchOrOperatorArgument(OrOperatorRhs);
  2082 |     MatchOrOperatorArgument(OrOperatorLhs);
  2083 |   }
  2084 | 
  2085 |   ICmpInst::Predicate Pred = Cmp.getPredicate();
  2086 |   auto BOpc = Pred == CmpInst::ICMP_EQ ? Instruction::And : Instruction::Or;
  2087 |   Value *LhsCmp = Builder.CreateICmp(Pred, CmpValues.rbegin()->first,
  2088 |                                      CmpValues.rbegin()->second);
  2089 | 
  2090 |   for (auto It = CmpValues.rbegin() + 1; It != CmpValues.rend(); ++It) {
  2091 |     Value *RhsCmp = Builder.CreateICmp(Pred, It->first, It->second);
  2092 |     LhsCmp = Builder.CreateBinOp(BOpc, LhsCmp, RhsCmp);
  2093 |   }
  2094 | 
  2095 |   return LhsCmp;
  2096 | }
