+    if (match(And, m_And(m_Value(X), m_APInt(Mask))) &&
+        Cmp.isEquality() &&
+        Mask->popcount() == Mask->getBitWidth() - 1 &&
+        C.isPowerOf2() && (C & ~*Mask) == 0) {
+      // Zero bit position is where Mask has 0.
+      // Since C's bit is not that zero bit (by the mask), we can simplify.
+      Value *AndC = Builder.CreateAnd(X, ConstantInt::get(X->getType(), C));
+      return new ICmpInst(Pred, AndC, ConstantInt::get(AndC->getType(), C));
+    }
+  }

   return nullptr;
 }
